queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?dance_recitals a :Dance_Recital .
    ?dance_recitals p:name ?name .
    ?dance_recitals p:Audition_Room ?audition_room_f .
    FILTER(STR(?audition_room_f) = "Room 101")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?talent_shows a :Talent_Show .
    ?talent_shows p:name ?name .
    ?talent_shows p:Audition_Room ?audition_room_f .
    FILTER(STR(?audition_room_f) = "Room 101")
    BIND(?name AS ?o0)
  }
}

